--
-- Table structure for table "invoice"
-- Creation Order: 2 - This table should be created after "order" table as it depends on "order"
--

DROP TABLE IF EXISTS "invoice";
CREATE TABLE "invoice" (
  id SERIAL PRIMARY KEY,
  order_id integer DEFAULT NULL,
  "invoiceDate" timestamp NOT NULL DEFAULT CURRENT_TIMESTAMP,
  "dueDate" timestamp DEFAULT NULL,
  tax decimal(19,4) DEFAULT 0.0000,
  shipping decimal(19,4) DEFAULT 0.0000,
  "amountDue" decimal(19,4) DEFAULT 0.0000
);

CREATE INDEX invoice_id_idx ON "invoice" (id);
CREATE INDEX "fkInvoicesOrder1_idx" ON "invoice" (order_id);
ALTER TABLE "invoice" ADD CONSTRAINT "fkInvoicesOrder1" 
  FOREIGN KEY (order_id) REFERENCES "durc_northwind_model"."order" (id) ON DELETE NO ACTION ON UPDATE NO ACTION;

